#include<bits/stdc++.h>
using namespace std;

int n,a[100001],dp[100001],w,v[100001];

int main(){
    cin>>w>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i]>>v[i];
        v[i]*=a[i];
    }for(int i=1;i<=n;i++){
        for(int j=w;j>=a[i];j--){
            if(j>=a[i]){
                dp[j]=max(dp[j],dp[j-a[i]]+v[i]);
            }
        }
    }cout<<dp[w];
}
